    auto globalMod = [](const uint64_t size, const std::vector<uint64_t>& v) { return size * v.at(0) / v.at(1); };
    tuner.AddThreadModifier(kernel, {def}, ktt::ModifierType::Global, ktt::ModifierDimension::X, {"MDIMC", "MWG"}, globalMod);
    tuner.AddThreadModifier(kernel, {def}, ktt::ModifierType::Global, ktt::ModifierDimension::Y, {"NDIMC", "NWG"}, globalMod);
