    auto multipleOfXY  = [&](const std::vector<uint64_t>& v) { return isMultiple(v[0], v[1] * v[2]); };
    auto multipleOfXYZ = [&](const std::vector<uint64_t>& v) { return isMultiple(v[0], (v[1] * v[2]) / v[3]); };
    tuner.AddConstraint(kernel, {"KWG", "KWI"}, [&](const std::vector<uint64_t>& v) { return isMultiple(v[0], v[1]); });
    tuner.AddConstraint(kernel, {"MWG", "MDIMC", "VWM"}, multipleOfXY);
